INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('red_flags', 'dvt_pe', ARRAY['DVT','ٹانگ سوجن','پنڈلی درد','سانس کی تکلیف','خون کا لوتھڑا'], 'DVT / پلمونری ایمبولزم', E'## DVT / پلمونری ایمبولزم\n\n**DVT علامات:** ایک ٹانگ میں سوجن، درد، سرخی، گرمی\n**PE علامات:** اچانک سانس کی تکلیف، سینے میں درد، کھانسی میں خون\n\n**خطرے کے عوامل:** سرجری، طویل بستر آرام، حمل، گولیاں، موٹاپا\n\n**فوری اقدامات:**\n- Wells Score کا حساب لگائیں\n- D-dimer اور Doppler الٹراساؤنڈ\n- اگر PE کا شبہ: CTPA فوری\n\n**⚠️ ہنگامی:** سانس کی شدید تکلیف + کم بلڈ پریشر → فوری ہسپتال منتقلی', 'ur', 'NICE/BTS', 10, true),
('red_flags', 'dka', ARRAY['DKA','ذیابیطس','شوگر بہت زیادہ','الٹی','پانی کی کمی'], 'ذیابیطس کیٹو ایسڈوسس', E'## ذیابیطس کیٹو ایسڈوسس (DKA)\n\n**علامات:** بہت زیادہ پیاس، بار بار پیشاب، الٹی، پیٹ درد، تیز سانس، بے ہوشی\n\n**تشخیص:**\n- بلڈ شوگر > 250 mg/dL\n- Blood pH < 7.3\n- کیٹونز مثبت\n\n**فوری علاج:**\n1. نارمل سیلائن IV تیز رفتار\n2. انسولین IV infusion\n3. پوٹاشیم کی نگرانی\n4. ہر گھنٹے شوگر چیک\n\n**⚠️ ہنگامی:** بے ہوشی، سانس Kussmaul، پھلوں جیسی سانس → ICU فوری', 'ur', 'ADA/WHO', 10, true),
('red_flags', 'ectopic_pregnancy', ARRAY['ایکٹوپک حمل','باہر رحم حمل','پیٹ درد','اندام نہانی خون'], 'ایکٹوپک حمل', E'## ایکٹوپک حمل\n\n**علامات:** پیٹ کے نچلے حصے میں درد (عام طور پر ایک طرف)، اندام نہانی سے خون آنا، چکر آنا\n\n**خطرے کے عوامل:** پہلا ایکٹوپک، PID، IUD، ٹیوبل سرجری\n\n**تشخیص:**\n- حمل ٹیسٹ مثبت\n- ٹرانس ویجائنل الٹراساؤنڈ\n- بیٹا hCG سیریل\n\n**⚠️ ہنگامی:** شدید پیٹ درد + کم بلڈ پریشر + تیز دھڑکن → فوری سرجری\n- ہیموڈائنامک عدم استحکام = فوری لیپروسکوپی', 'ur', 'RCOG/NICE', 10, true),
('red_flags', 'acute_abdomen', ARRAY['شدید پیٹ درد','تیز پیٹ','اپنڈکس','آنتوں کی رکاوٹ'], 'شدید پیٹ درد', E'## شدید پیٹ درد (Acute Abdomen)\n\n**فوری خطرناک اسباب:**\n- اپنڈیسائٹس: دائیں نچلا حصہ\n- آنتوں کی رکاوٹ: الٹی + پیٹ پھولنا + قبض\n- پیریٹونائٹس: سخت پیٹ، حرکت سے درد\n- AAA پھٹنا: بزرگ + پیٹ/کمر درد + کم BP\n\n**فحوصات:** CBC، ایمائلیز، لیکٹیٹ، پیٹ ایکسرے، CT\n\n**⚠️ فوری سرجری:** سخت پیٹ + بخار + تیز دھڑکن → سرجیکل ایمرجنسی', 'ur', 'ATLS/Clinical', 10, true),
('red_flags', 'meningitis', ARRAY['گردن توڑ بخار','سحایا','بخار','گردن اکڑن','ددورے'], 'سحایا (گردن توڑ بخار)', E'## سحایا (Meningitis)\n\n**علامات:** تیز بخار، شدید سر درد، گردن اکڑن، روشنی سے تکلیف، الٹی\n\n**بچوں میں:** چڑچڑاپن، فانٹنیل ابھرا ہوا، کم دودھ پینا\n\n**اہم ٹیسٹ:** دبانے پر نہ مٹنے والے ددورے (Glass test)\n\n**فوری علاج:**\n- سیفٹریکسون 2g IV فوری (تشخیص سے پہلے بھی)\n- ڈیکسامیتھازون 0.15 mg/kg\n- لمبر پنکچر (اگر محفوظ ہو)\n\n**⚠️ ہنگامی:** بے ہوشی + ددورے + جھٹکا → ICU فوری', 'ur', 'NICE/WHO', 10, true),
('red_flags', 'sepsis', ARRAY['سیپسس','خون میں زہر','بخار','کم بلڈ پریشر'], 'سیپسس', E'## سیپسس\n\n**شناخت (qSOFA):**\n- سسٹولک BP ≤ 100\n- سانس ≥ 22/منٹ\n- شعور میں تبدیلی\n\n**2 یا زیادہ = سیپسس کا شبہ**\n\n**فوری اقدامات (Sepsis-6 ایک گھنٹے میں):**\n1. خون میں لیکٹیٹ\n2. بلڈ کلچر\n3. IV اینٹی بائیوٹک\n4. IV سیلائن 30 mL/kg\n5. آکسیجن\n6. پیشاب کی پیمائش\n\n**⚠️ ہنگامی:** لیکٹیٹ > 4 + کم BP → سیپٹک شاک → ICU + vasopressors', 'ur', 'SSC/NICE', 10, true),
('red_flags', 'stroke', ARRAY['فالج','لقوا','بولنے میں مشکل','چہرے کا ٹیڑھا'], 'فالج (اسٹروک)', E'## فالج (Stroke)\n\n**FAST شناخت:**\n- **F**ace: چہرے کا ایک طرف جھکنا\n- **A**rms: بازو اٹھانے میں کمزوری\n- **S**peech: بولنے میں مشکل\n- **T**ime: فوری ہسپتال\n\n**وقت کی اہمیت:**\n- 4.5 گھنٹے کے اندر: thrombolysis (tPA)\n- 6-24 گھنٹے: thrombectomy ممکن\n\n**فوری فحوصات:** CT دماغ (خون بہنا خارج کرنے کے لیے)\n\n**⚠️ ہنگامی:** کوئی بھی FAST علامت → فوری ایمبولینس', 'ur', 'AHA/ASA', 10, true),
('red_flags', 'acute_mi', ARRAY['دل کا دورہ','سینے میں درد','ہارٹ اٹیک','MI'], 'دل کا دورہ', E'## دل کا دورہ (Acute MI)\n\n**علامات:** سینے میں دبنے والا درد > 20 منٹ، بائیں بازو/جبڑے تک، پسینہ، الٹی\n\n**فوری اقدامات:**\n1. ایسپرین 300 mg چبائیں\n2. GTN زیر زبان\n3. آکسیجن (SpO2 < 94%)\n4. مورفین (درد نہ رکے تو)\n5. ECG فوری (12 لیڈ)\n\n**STEMI:** فوری PCI (90 منٹ) یا thrombolysis (30 منٹ)\n\n**⚠️ ہنگامی:** سینے میں دبنے والا درد + پسینہ + بے چینی → فوری ایمرجنسی', 'ur', 'AHA/ESC', 10, true),
('red_flags', 'suicidal_ideation', ARRAY['خودکشی','موت کی خواہش','خود کو نقصان','ذہنی صحت'], 'خودکشی کے خیالات', E'## خودکشی کے خیالات\n\n**فوری خطرے کی علامات:**\n- مخصوص منصوبہ بنا رکھا ہے\n- ذرائع تک رسائی (دوائیں، ہتھیار)\n- الوداعی پیغامات\n- پہلے کوشش کر چکے ہیں\n\n**اقدامات:**\n1. مریض کو اکیلا نہ چھوڑیں\n2. خطرناک چیزیں ہٹائیں\n3. براہ راست پوچھیں (سوال پوچھنا خطرہ نہیں بڑھاتا)\n4. فوری نفسیاتی حوالہ\n\n**⚠️ ہنگامی:** فعال منصوبہ + ذرائع = فوری نفسیاتی ایمرجنسی\n\n**ہیلپ لائن:** نزدیکی ذہنی صحت مرکز سے رابطہ', 'ur', 'WHO/NICE', 10, true),
('red_flags', 'hypertensive_crisis', ARRAY['بلڈ پریشر بہت زیادہ','ہائپرٹینسو','سر درد','ناک سے خون'], 'ہائپرٹینسیو ایمرجنسی', E'## ہائپرٹینسیو ایمرجنسی\n\n**تعریف:** BP > 180/120 + اعضاء کو نقصان\n\n**اعضاء کو نقصان:**\n- دماغ: شدید سر درد، بینائی دھندلی، الجھن\n- دل: سینے میں درد، سانس تکلیف\n- گردے: پیشاب کم\n\n**فوری علاج:**\n- IV labetalol یا nicardipine\n- پہلے گھنٹے میں MAP 25% کم کریں\n- زیادہ تیزی سے کم نہ کریں\n\n**⚠️ ہنگامی:** BP > 180/120 + سر درد + بینائی تبدیلی → فوری ICU', 'ur', 'AHA/JNC', 10, true),
('red_flags', 'hypoglycemia', ARRAY['شوگر کم','ہائپوگلائسیمیا','کانپنا','بے ہوشی'], 'شدید ہائپوگلائسیمیا', E'## شدید ہائپوگلائسیمیا\n\n**علامات:**\n- ہلکی: کانپنا، پسینہ، بھوک، دھڑکن\n- شدید: الجھن، جھٹکے، بے ہوشی\n\n**فوری علاج:**\n- ہوش ہے: 15-20g گلوکوز (جوس، مٹھائی)\n- 15 منٹ بعد دوبارہ چیک کریں\n- ہوش نہیں: IV Dextrose 50% یا IM Glucagon 1mg\n\n**اسباب:** انسولین زیادہ، کھانا نہیں کھایا، ورزش زیادہ، گردے فیل\n\n**⚠️ ہنگامی:** بے ہوشی + شوگر < 54 mg/dL → IV Dextrose فوری', 'ur', 'ADA/NICE', 10, true),
('red_flags', 'acute_asthma', ARRAY['دمہ کا شدید حملہ','سانس','بخاخ','آکسیجن'], 'دمہ کا شدید حملہ', E'## دمہ کا شدید حملہ\n\n**شدت کا اندازہ:**\n- اعتدال پسند: بات کر سکتا ہے، PEF 50-75%\n- شدید: بات نہیں کر سکتا، PEF 33-50%\n- جان لیوا: خاموش سینہ، SpO2 < 92%، الجھن\n\n**فوری علاج:**\n1. سالبوٹامول 10 پف spacer سے (یا نیبولائزر 5mg)\n2. آکسیجن SpO2 > 94% رکھیں\n3. پریڈنیزولون 40mg فوری\n4. Ipratropium نیبولائزر\n\n**⚠️ ہنگامی:** خاموش سینہ + تھکاوٹ + SpO2 < 92% → ICU + IV magnesium', 'ur', 'BTS/GINA', 10, true),
('red_flags', 'testicular_torsion', ARRAY['خصیے میں درد','خصیہ مڑنا','اچانک درد'], 'خصیے کا ٹورشن', E'## خصیے کا ٹورشن\n\n**علامات:** اچانک شدید درد خصیے میں، متلی، الٹی\n\n**شناخت:**\n- خصیہ اوپر کھنچا ہوا\n- Cremasteric reflex غائب\n- عمر: عام طور پر 12-25 سال\n\n**وقت بہت اہم:**\n- 6 گھنٹے کے اندر سرجری = 90% بچاؤ\n- 12 گھنٹے بعد = 50% بچاؤ\n- 24 گھنٹے بعد = خصیہ ضائع\n\n**⚠️ ہنگامی:** نوجوان + اچانک خصیے میں درد → فوری سرجیکل حوالہ (الٹراساؤنڈ کا انتظار نہ کریں)', 'ur', 'EAU/Clinical', 10, true),
('red_flags', 'placental_abruption', ARRAY['نال الگ ہونا','حمل میں خون','پیٹ درد','رحم سخت'], 'نال کا الگ ہونا', E'## نال کا الگ ہونا (Placental Abruption)\n\n**علامات:** اچانک اندام نہانی سے خون، مسلسل پیٹ درد، رحم سخت\n\n**خطرے کے عوامل:** ہائی بلڈ پریشر، صدمہ، تمباکو نوشی، پہلے abruption\n\n**تشخیص:** طبی شناخت + CTG + الٹراساؤنڈ\n\n**فوری اقدامات:**\n1. دو بڑی IV لائنیں\n2. خون کی ترتیب\n3. CTG مسلسل\n4. ماہر امراض نسواں کو بلائیں\n\n**⚠️ ہنگامی:** بہت زیادہ خون + بچے کی دھڑکن خراب → ایمرجنسی سیزیرین', 'ur', 'RCOG', 10, true),
('red_flags', 'acute_glaucoma', ARRAY['آنکھ درد','گلوکوما','بینائی دھندلی','آنکھ سرخ'], 'شدید گلوکوما', E'## شدید زاویہ بند گلوکوما\n\n**علامات:** آنکھ میں شدید درد، سر درد، متلی، الٹی، بینائی دھندلی، روشنی کے گرد ہالے\n\n**معائنہ:**\n- آنکھ سرخ\n- پتلی بڑی اور ردعمل نہیں دیتی\n- آنکھ دبانے پر سخت\n\n**فوری علاج:**\n1. Pilocarpine 2% قطرے ہر 5 منٹ × 3\n2. Timolol 0.5% قطرے\n3. Acetazolamide 500mg IV/زبانی\n4. فوری آنکھوں کے ڈاکٹر کو حوالہ\n\n**⚠️ ہنگامی:** اگر علاج نہ ہو تو مستقل بینائی ضائع', 'ur', 'AAO/NICE', 10, true),
('red_flags', 'aortic_dissection', ARRAY['شہ رگ پھٹنا','سینے میں چیرنے والا درد','کمر درد شدید'], 'شہ رگ کا پھٹنا', E'## شہ رگ کا پھٹنا (Aortic Dissection)\n\n**علامات:** سینے/کمر میں اچانک شدید چیرنے والا درد\n\n**اہم علامات:**\n- دونوں بازوؤں میں BP فرق > 20 mmHg\n- نبض غائب\n- اعصابی علامات\n\n**فوری اقدامات:**\n1. IV labetalol (HR < 60, SBP < 120)\n2. CT angiography فوری\n3. کارڈیک سرجن سے رابطہ\n\n**⚠️ ہنگامی:** اچانک چیرنے والا درد + BP فرق → Type A = فوری سرجری', 'ur', 'AHA/ESC', 10, true),
('red_flags', 'tension_pneumothorax', ARRAY['ہوا جمع سینے میں','سانس تکلیف','ٹینشن نیومو'], 'ٹینشن نیوموتھوریکس', E'## ٹینشن نیوموتھوریکس\n\n**علامات:** شدید سانس تکلیف، سینے میں درد، کم BP، گلے کی نسیں ابھری\n\n**معائنہ:**\n- متاثرہ طرف سانس کی آواز غائب\n- ٹریکیا دوسری طرف کھسکا\n- متاثرہ سینہ پھولا\n\n**فوری علاج:**\n- انتظار نہ کریں - طبی تشخیص پر عمل\n- سوئی سے ہوا نکالیں (2nd intercostal space, midclavicular)\n- پھر chest drain لگائیں\n\n**⚠️ ہنگامی:** یہ ایک جان لیوا ایمرجنسی ہے → فوری decompression', 'ur', 'ATLS/BTS', 10, true),
('red_flags', 'status_epilepticus', ARRAY['مسلسل دورے','مرگی','تشنج','فٹس'], 'اسٹیٹس ایپیلیپٹیکس', E'## مسلسل دورے (Status Epilepticus)\n\n**تعریف:** 5 منٹ سے زیادہ دورے یا دوروں کے درمیان ہوش نہ آنا\n\n**فوری اقدامات:**\n0-5 منٹ: ایئر وے محفوظ، آکسیجن، ٹائم نوٹ\n5-10 منٹ: Midazolam IM 10mg یا Diazepam IV 10mg\n10-20 منٹ: Levetiracetam 60mg/kg یا Phenytoin 20mg/kg IV\n20+ منٹ: RSI + ICU\n\n**⚠️ ہنگامی:** 5 منٹ سے زیادہ دورے → فوری بینزوڈائزیپین + ایمبولینس', 'ur', 'NICE/AES', 10, true),
('red_flags', 'anaphylaxis', ARRAY['شدید الرجی','سانس بند','سوجن','ایپینیفرین'], 'شدید الرجی (Anaphylaxis)', E'## شدید الرجی (Anaphylaxis)\n\n**علامات:** سانس تکلیف، گلے/زبان سوجن، ددورے، چکر، کم BP\n\n**فوری علاج:**\n1. **ایپینیفرین IM 0.5mg** (ران کے باہری حصے میں) - فوری!\n2. 999/ایمبولینس کال کریں\n3. مریض لٹائیں، ٹانگیں اوپر\n4. آکسیجن + IV سیلائن\n5. 5 منٹ بعد بہتری نہ ہو تو ایپینیفرین دوبارہ\n\n**⚠️ ہنگامی:** ایپینیفرین پہلی دوا ہے - تاخیر جان لیوا ہو سکتی ہے', 'ur', 'Resus Council/NICE', 10, true),
('red_flags', 'cord_prolapse', ARRAY['نال باہر آنا','ہنگامی ڈیلیوری','نال کا پھسلنا'], 'نال کا باہر آنا (Cord Prolapse)', E'## نال کا باہر آنا\n\n**شناخت:** پانی ٹوٹنے کے بعد نال اندام نہانی میں محسوس یا نظر\n\n**فوری اقدامات:**\n1. نال کو دبائیں نہیں\n2. ہاتھ سے بچے کا سر نال سے دور رکھیں\n3. ماں کو گھٹنوں پر سینے کے بل (knee-chest)\n4. مسلسل CTG\n5. فوری سیزیرین\n\n**⚠️ ہنگامی:** یہ ایک سرجیکل ایمرجنسی ہے → منٹوں میں سیزیرین ضروری', 'ur', 'RCOG', 10, true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('red_flags', 'major_hemorrhage', ARRAY['بہت زیادہ خون بہنا','خون کا ضیاع','شاک'], 'شدید خون بہنا', E'## شدید خون بہنا\n\n**علامات:** تیز دھڑکن، کم BP، پیلا، ٹھنڈا پسینہ، بے چینی\n\n**فوری اقدامات:**\n1. براہ راست دباؤ سے خون روکیں\n2. ٹانگیں اوپر\n3. دو بڑی IV لائنیں\n4. O-negative خون تیار\n5. Tranexamic acid 1g IV\n\n**⚠️ ہنگامی:** فعال خون بہنا + تیز دھڑکن + کم BP → Massive transfusion protocol شروع کریں', 'ur', 'ATLS/WHO', 10, true),
('red_flags', 'pediatric_sepsis', ARRAY['بچوں میں سیپسس','بچے میں بخار','نیل پڑنا','بے چینی'], 'بچوں میں سیپسس', E'## بچوں میں سیپسس\n\n**شناخت:**\n- بخار یا کم درجہ حرارت\n- تیز دھڑکن (عمر کے لحاظ سے)\n- تیز سانس\n- نیل پڑنا یا دھبے\n- بے چینی یا سستی\n- capillary refill > 3 سیکنڈ\n\n**فوری اقدامات:**\n1. آکسیجن\n2. IV/IO رسائی\n3. سیلائن بولس 20mL/kg\n4. اینٹی بائیوٹک فوری\n5. شوگر چیک کریں\n\n**⚠️ ہنگامی:** بچے میں ددورے + بخار + سستی → سحایا فرض کریں → سیفٹریکسون فوری', 'ur', 'NICE/SSC', 10, true),
('red_flags', 'acute_kidney_injury', ARRAY['گردے فیل','پیشاب نہ آنا','کریٹینین بڑھا'], 'شدید گردے کی خرابی', E'## شدید گردے کی خرابی (AKI)\n\n**شناخت:**\n- پیشاب < 0.5 mL/kg/hr × 6 گھنٹے\n- کریٹینین میں اچانک اضافہ\n\n**اسباب:**\n- پانی کی کمی (سب سے عام)\n- سیپسس\n- دوائیں (NSAIDs، aminoglycosides)\n- رکاوٹ (پتھری، پروسٹیٹ)\n\n**فوری اقدامات:**\n1. IV سیلائن (اگر پانی کی کمی)\n2. نقصان دہ دوائیں بند کریں\n3. پوٹاشیم چیک (اگر > 6.5 → ایمرجنسی)\n4. الٹراساؤنڈ (رکاوٹ خارج کرنے کے لیے)\n\n**⚠️ ہنگامی:** پوٹاشیم > 6.5 یا pulmonary edema → فوری ڈائلیسس', 'ur', 'KDIGO/NICE', 10, true),
('red_flags', 'bowel_obstruction', ARRAY['آنتوں کی رکاوٹ','پیٹ پھولنا','الٹی','قبض'], 'آنتوں کی رکاوٹ', E'## آنتوں کی رکاوٹ\n\n**علامات:** پیٹ پھولنا، الٹی (پت یا فضلہ), مکمل قبض، مروڑ والا درد\n\n**اسباب:** adhesions، ہرنیا، ٹیومر، volvulus\n\n**تشخیص:** پیٹ ایکسرے (ہوا کی سطحیں)، CT\n\n**فوری اقدامات:**\n1. NPO (منہ سے کچھ نہیں)\n2. NG ٹیوب\n3. IV سیلائن\n4. سرجیکل مشورہ\n\n**⚠️ ہنگامی:** بخار + سخت پیٹ + تیز دھڑکن → آنت مری (strangulation) → فوری سرجری', 'ur', 'Clinical/ATLS', 10, true),
('red_flags', 'postpartum_hemorrhage', ARRAY['زچگی کے بعد خون','PPH','بچے کی پیدائش کے بعد خون'], 'زچگی کے بعد خون بہنا', E'## زچگی کے بعد خون بہنا (PPH)\n\n**تعریف:** 500mL سے زیادہ خون کا ضیاع (سیزیرین: 1000mL)\n\n**4 T اسباب:**\n- **T**one: رحم ڈھیلا (سب سے عام)\n- **T**rauma: پھٹنا\n- **T**issue: نال کا حصہ رہ گیا\n- **T**hrombin: خون جمنے کا مسئلہ\n\n**فوری اقدامات:**\n1. رحم کی مالش (bimanual)\n2. Oxytocin 40 IU IV\n3. Tranexamic acid 1g IV\n4. دو بڑی IV لائنیں + خون\n\n**⚠️ ہنگامی:** 1000mL سے زیادہ خون → Massive transfusion + سرجری', 'ur', 'WHO/RCOG', 10, true),
('red_flags', 'acute_coronary_syndrome', ARRAY['ACS','دل کی نالی بند','unstable angina','سینے میں تکلیف'], 'ایکیوٹ کورونری سنڈروم', E'## ACS - دل کی شریانوں کا بحران\n\n**اقسام:**\n- STEMI: مکمل بندش → فوری PCI\n- NSTEMI: جزوی بندش → 72 گھنٹے میں angiography\n- Unstable Angina: ٹروپونین نارمل\n\n**فوری MONA:**\n- Morphine (اگر درد شدید)\n- Oxygen (SpO2 < 94%)\n- Nitrate (GTN زیر زبان)\n- Aspirin 300mg + Clopidogrel 300mg\n\n**⚠️ ہنگامی:** ECG فوری → STEMI → PCI 90 منٹ میں', 'ur', 'AHA/ESC', 10, true);
